scwin.f_Retrieve = async function () {
  //validation check
  if (acb_qryConKnd.getValue() == "YM") {
    if (!(await $c.gus.cfValidate($p, [ed_homeClntNo, ica_adptYm]))) {
      return;
    }
  } else {
    if (!(await $c.gus.cfValidate($p, [ed_homeClntNo, ica_qryConDtFm, ica_qryConDtTo]))) {
      return;
    }

    //조회시작일자가 더 클경우 체크
    if (!(await $c.gus.cfIsAfterDate($p, ica_qryConDtFm.getValue(), ica_qryConDtTo.getValue()))) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
      return;
    }
  }
  $c.sbm.execute($p, sbm_retrieve);
};

